### Integration Tests (`apps/gateway/tests/integration/ru-websocket.test.ts`)

```typescript
describe("RU WebSocket Integration", () => {
  it("should receive real-time sync progress", async () => {
    const ws = await connectTestWebSocket();
    await ws.subscribe("fleet:sync:test_session");

    const events: RUEvent[] = [];
    ws.onMessage((event) => events.push(event));

    // Trigger sync
    await startFleetSync("test", { filter: { repos: ["repo_1"] } });

    // Wait for events
    await waitFor(() => events.length >= 2, 10000);

    expect(events.some(e => e.type === "ru.sync_repo_started")).toBe(true);
    expect(events.some(e => e.type === "ru.sync_repo_completed")).toBe(true);

    logger.info({
      testName: "realtime_sync_progress",
      eventCount: events.length,
      eventTypes: events.map(e => e.type),
      correlationId: getCorrelationId(),
    }, "Real-time sync events received");

    await ws.close();
  });

  it("should receive sweep plan events", async () => {
    const session = await startAgentSweep("test", { targetRepos: "*", autoApprove: true });

    const ws = await connectTestWebSocket();
    await ws.subscribe(`fleet:sweep:${session.id}`);

    const events: RUEvent[] = [];
    ws.onMessage((event) => events.push(event));

    // Wait for phase 2 to create plans
    await waitFor(() => events.some(e => e.type === "ru.sweep_plan_created"), 60000);

    const planEvent = events.find(e => e.type === "ru.sweep_plan_created") as RUSweepPlanCreatedEvent;
    expect(planEvent.data.sessionId).toBe(session.id);
    expect(planEvent.data.planId).toBeDefined();

    logger.info({
      testName: "sweep_plan_events",
      sessionId: session.id,
      eventCount: events.length,
      correlationId: getCorrelationId(),
    }, "Sweep plan events received");

    await ws.close();
  });
});
